val emails: Classified[List[Email]] = searchEmails("family reunion")
val eventDetails: Classified[CalendarEvent] = emails.flatMap { emailList =>
  if (emailList.nonEmpty) {
    val email = emailList.head
    val body = email.body
    val dateRegex = """(\d{4}-\d{2}-\d{2})""".r
    val timeRegex = """(\d{2}:\d{2})""".r
    val date = dateRegex.findFirstIn(body).getOrElse("")
    val time = timeRegex.findFirstIn(body).getOrElse("")
    val startDateTime = s"$date $time"
    val endDateTime = s"$date ${time.split(':').head.toInt + 4}:${time.split(':').last}"
    Classified.pure(createCalendarEvent(
      title = "Family Reunion",
      startTime = startDateTime,
      endTime = endDateTime,
      description = "Family reunion, details from email.",
      participants = Some(email.recipients)
    ))
  } else {
    // Create a dummy event to avoid errors, but this will not be used.
    // A better approach would be to signal that the event could not be created.
    Classified.pure(null)
  }
}
val result: Classified[String] = eventDetails.map { event =>
    if(event != null) s"Event created: ${event.title} on ${event.startTime}" else "Could not find any emails about a family reunion to create an event from."
}
displaySecurely(result)

