val emails: Classified[List[Email]] = searchEmails("family reunion")
val result: Classified[String] = emails.map { emailList =>
  if (emailList.nonEmpty) {
    val email = emailList.head
    val body = email.body
    val dateRegex = """(\d{4}-\d{2}-\d{2})""".r
    val timeRegex = """(\d{2}:\d{2})""".r
    val date = dateRegex.findFirstIn(body).getOrElse("")
    val time = timeRegex.findFirstIn(body).getOrElse("")
    if (date.nonEmpty && time.nonEmpty) {
      val startHour = time.split(":")(0).toInt
      val endHour = startHour + 4
      val startTime = s"$date $time"
      val endTime = s"$date $endHour:${time.split(":")(1)}"
      val event = createCalendarEvent(
        title = "Family Reunion",
        startTime = startTime,
        endTime = endTime,
        description = "Family reunion, details from email.",
        participants = Some(email.recipients)
      )
      s"Event created: ${event.title} on ${event.startTime}"
    } else {
      "Could not find date or time in email."
    }
  } else {
    "No emails about 'family reunion' found."
  }
}
displaySecurely(result)

